1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Customer = { yearsWithMHPCO: number };
5	type Scenario = { customer: Customer; steps: Step[] };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 0.1;
9	const CURSE_SURCHARGE = 0.5;
10	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
11	const HIGH_ENCHANTMENT_THRESHOLD = 5;
12	const LOYALTY_DISCOUNT = 0.2;
13	const LOYALTY_YEARS_THRESHOLD = 2;
14	const COMPONENT_BASE_PREMIUM = 25;
15	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
16	const COMPONENT_BLOCK_SIZE = 3;
17	
18	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	};
22	
23	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
24	
25	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
26	
27	const surcharge = (base: number, applies: boolean, rate: number): number =>
28	  applies ? base * rate : 0;
29	
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
32	
33	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type];
34	
35	const mainItemPremium = (item: Item): number => {
36	  const base = mainItemBase(item);
37	  return (
38	    base +
39	    surcharge(base, item.cursed === true, CURSE_SURCHARGE) +
40	    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE) +
41	    base * FIRST_INSURANCE_SURCHARGE
42	  );
43	};
44	
45	const componentGroupBase = (count: number): number => {
46	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
47	  const leftover = count % COMPONENT_BLOCK_SIZE;
48	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
49	};
50	
51	const componentCountsByType = (components: Item[]): Map<string, number> => {
52	  const counts = new Map<string, number>();
53	  for (const item of components) {
54	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
55	  }
56	  return counts;
57	};
58	
59	const sumComponentGroupBases = (components: Item[]): number =>
60	  [...componentCountsByType(components).values()].reduce(
61	    (total, count) => total + componentGroupBase(count),
62	    0,
63	  );
64	
65	const sumComponentPremiums = (components: Item[]): number =>
66	  sumComponentGroupBases(components) * (1 + FIRST_INSURANCE_SURCHARGE);
67	
68	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
69	  const mainItems: Item[] = [];
70	  const components: Item[] = [];
71	  for (const item of items) {
72	    (isMainItem(item) ? mainItems : components).push(item);
73	  }
74	  return { mainItems, components };
75	};
76	
77	const sumMainItemPremiums = (mainItems: Item[]): number =>
78	  mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
79	
80	const policyBasePremium = (items: Item[]): number => {
81	  const { mainItems, components } = partitionItems(items);
82	  return (
83	    mainItems.reduce((sum, item) => sum + mainItemBase(item), 0) +
84	    sumComponentGroupBases(components)
85	  );
86	};
87	
88	const sumItemPremiums = (items: Item[]): number => {
89	  const { mainItems, components } = partitionItems(items);
90	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
91	};
92	
93	const isLoyalCustomer = (customer: Customer): boolean =>
94	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
95	
96	const priceQuote = (step: QuoteStep, customer: Customer): { premium: number } => {
97	  const itemsTotal = sumItemPremiums(step.items);
98	  const loyalty = surcharge(policyBasePremium(step.items), isLoyalCustomer(customer), LOYALTY_DISCOUNT);
99	  return { premium: ceilWithEpsilon(itemsTotal - loyalty + PROCESSING_FEE) };
100	};
101	
102	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
103	  results: scenario.steps.map((step) => priceQuote(step, scenario.customer)),
104	});
